    [Route("api/[controller]")]
    [ApiController]
    public class UploadController : ControllerBase
    {
        private static readonly string[] permittedExtensions = { ".jpg", ".jpeg", ".png", ".gif", ".pdf", ".doc", ".docx", ".xls", ".xlsx" };
        private readonly long _fileSizeLimit = 10 * 1024 * 1024; // 10 MB
        private readonly string _uploadFolder = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot/uploads");

        [HttpPost("upload-file")]
        public async Task<IActionResult> UploadFile(IFormFile file)
        {
            if (file == null || file.Length == 0)
            {
                return BadRequest("No file uploaded.");
            }

            if (file.Length > _fileSizeLimit)
            {
                return BadRequest("File size exceeds the limit.");
            }

            var fileExtension = Path.GetExtension(file.FileName).ToLowerInvariant();
            if (Array.IndexOf(permittedExtensions, fileExtension) < 0)
            {
                return BadRequest("Unsupported file type.");
            }

            var filePath = Path.Combine(_uploadFolder, Guid.NewGuid() + fileExtension);
            Directory.CreateDirectory(_uploadFolder);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            var fileUrl = $"{Request.Scheme}://{Request.Host}/uploads/{Path.GetFileName(filePath)}";
            return Ok(new { filePath = fileUrl });
